      }, 
      get: (q, p, cb) => cb(null, null),
      serialize: (cb) => cb(),
      prepare: function() {
        return {
          run: function(p, cb) {
            if (cb) cb.call({ lastID: 1 }, null);
          },
          finalize: function() {}
        };
      }
